  1→/**
  2→ * SKF Agent Compiler
  3→ * Compiles agent YAML to activated Markdown with embedded XML.
  4→ * Adapted from BMAD's standard agent compilation pipeline.
  5→ */
  6→
  7→const yaml = require('js-yaml');
  8→const fs = require('node:fs');
  9→const path = require('node:path');
 10→
 11→// --- XML Utility ---
 12→
 13→function escapeXml(text) {
 14→  if (!text) return '';
 15→  return text.replaceAll('&', '&amp;').replaceAll('<', '&lt;').replaceAll('>', '&gt;').replaceAll('"', '&quot;').replaceAll("'", '&apos;');
 16→}
 17→
 18→// --- XML Builder Functions ---
 19→
 20→function buildFrontmatter(metadata, agentName) {
 21→  const nameFromFile = agentName.replaceAll('-', ' ');
 22→  const description = metadata.title || 'SKF Agent';
 23→
 24→  return `---
 25→name: "${nameFromFile}"
 26→description: "${description}"
 27→---
 28→
 29→You must fully embody this agent's persona and follow all activation instructions exactly as specified. NEVER break character until given an exit command.
 30→
 31→`;
 32→}
 33→
 34→function buildPersonaXml(persona) {
 35→  if (!persona) return '';
 36→
 37→  let xml = '  <persona>\n';
 38→
 39→  const fields = ['role', 'identity', 'communication_style', 'working_style'];
 40→  for (const field of fields) {
 41→    if (persona[field]) {
 42→      const text = persona[field].trim().replaceAll(/\n+/g, ' ').replaceAll(/\s+/g, ' ');
 43→      xml += `    <${field}>${escapeXml(text)}</${field}>\n`;
 44→    }
 45→  }
 46→
 47→  if (persona.principles) {
 48→    let principlesText;
 49→    if (Array.isArray(persona.principles)) {
 50→      principlesText = persona.principles.join(' ');
 51→    } else {
 52→      principlesText = persona.principles.trim().replaceAll(/\n+/g, ' ');
 53→    }
 54→    xml += `    <principles>${escapeXml(principlesText)}</principles>\n`;
 55→  }
 56→
 57→  xml += '  </persona>\n';
 58→  return xml;
 59→}
 60→
 61→function buildPromptsXml(prompts) {
 62→  if (!prompts || prompts.length === 0) return '';
 63→
 64→  let xml = '  <prompts>\n';
 65→  for (const prompt of prompts) {
 66→    xml += `    <prompt id="${prompt.id || ''}">\n`;
 67→    xml += '      <content>\n';
 68→    xml += `${prompt.content || ''}\n`;
 69→    xml += '      </content>\n';
 70→    xml += '    </prompt>\n';
 71→  }
 72→  xml += '  </prompts>\n';
 73→  return xml;
 74→}
 75→
 76→function buildMemoriesXml(memories) {
 77→  if (!memories || memories.length === 0) return '';
 78→
 79→  let xml = '  <memories>\n';
 80→  for (const memory of memories) {
 81→    xml += `    <memory>${escapeXml(String(memory))}</memory>\n`;
 82→  }
 83→  xml += '  </memories>\n';
 84→  return xml;
 85→}
 86→
 87→function detectUsedHandlers(menuItems) {
 88→  const used = new Set();
 89→  if (!menuItems) return used;
 90→
 91→  for (const item of menuItems) {
 92→    if (item.workflow) used.add('workflow');
 93→    if (item.exec) used.add('exec');
 94→    if (item.data) used.add('data');
 95→    if (item.action) used.add('action');
 96→    if (item.multi) used.add('multi');
 97→  }
 98→  return used;
 99→}
100→
101→function buildActivationBlock(agent, skfFolder) {
102→  const criticalActions = agent.critical_actions || [];
103→
104→  let stepNum = 4;
105→  let agentSteps = '';
106→  for (const action of criticalActions) {
107→    agentSteps += `    <step n="${stepNum}">${action}</step>\n`;
108→    stepNum++;
109→  }
110→
111→  const menuStep = stepNum;
112→  const haltStep = stepNum + 1;
113→  const inputStep = stepNum + 2;
114→  const executeStep = stepNum + 3;
115→
116→  let xml = `  <activation critical="MANDATORY">
117→    <step n="1">Load persona from this current agent file (already in context)</step>
118→    <step n="2">IMMEDIATE ACTION REQUIRED - BEFORE ANY OUTPUT:
119→        - Load and read {project-root}/${skfFolder}/config.yaml NOW
120→        - Store ALL fields as session variables: {user_name}, {communication_language}, {skills_output_folder}, {forge_data_folder}, {project_name}
121→        - VERIFY: If config not loaded, STOP and report error to user
122→        - DO NOT PROCEED to step 3 until config is successfully loaded and variables stored
123→    </step>
124→    <step n="3">Remember: user's name is {user_name}</step>
125→${agentSteps}    <step n="${menuStep}">Show greeting using {user_name} from config, communicate in {communication_language}, then display numbered list of ALL menu items from menu section</step>
126→    <step n="${haltStep}">STOP and WAIT for user input - do NOT execute menu items automatically - accept number or cmd trigger or fuzzy command match</step>
127→    <step n="${inputStep}">On user input: Number -> execute menu item[n] | Text -> case-insensitive substring match | Multiple matches -> ask user to clarify | No match -> show "Not recognized"</step>
128→    <step n="${executeStep}">When executing a menu item: Check menu-handlers section below - extract any attributes from the selected menu item (workflow, exec, data, action) and follow the corresponding handler instructions</step>
129→
130→    <menu-handlers>
131→      <handlers>
132→`;
133→
134→  const used = detectUsedHandlers(agent.menu);
135→
136→  if (used.has('workflow')) {
137→    xml += `    <handler type="workflow">
138→      When menu item has: workflow="path/to/workflow.md":
139→      1. Load and read the complete workflow file at the specified path
140→      2. Follow all steps and instructions within the workflow file precisely
141→      3. Save outputs after completing EACH workflow step (never batch multiple steps together)
142→      4. If workflow path is "todo", inform user the workflow hasn't been implemented yet
143→    </handler>
144→`;
145→  }
146→
147→  if (used.has('exec')) {
148→    xml += `    <handler type="exec">
149→      When menu item or handler has: exec="path/to/file.md":
150→      1. Actually LOAD and read the entire file and EXECUTE the file at that path - do not improvise
151→      2. Read the complete file and follow all instructions within it
152→      3. If there is data="some/path/data-foo.md" with the same item, pass that data path to the executed file as context.
153→    </handler>
154→`;
155→  }
156→
157→  if (used.has('data')) {
158→    xml += `    <handler type="data">
159→      When menu item has: data="path/to/file.json|yaml|yml|csv|xml"
160→      Load the file first, parse according to extension
161→      Make available as {data} variable to subsequent handler operations
162→    </handler>
163→`;
164→  }
165→
166→  if (used.has('action')) {
167→    xml += `    <handler type="action">
168→      When menu item has: action="#id" -> Find prompt with id="id" in current agent XML, execute its content
169→      When menu item has: action="text" -> Execute the text directly as an inline instruction
170→    </handler>
171→`;
172→  }
173→
174→  if (used.has('multi')) {
175→    xml += `    <handler type="multi">
176→       When menu item has: type="multi" with nested handlers
177→       1. Display the multi item text as a single menu option
178→       2. Parse all nested handlers within the multi item
179→       3. For each nested handler:
180→          - Use the 'match' attribute for fuzzy matching user input (or Exact Match of character code in brackets [])
181→          - Execute based on handler attributes (exec, workflow, action)
182→       4. When user input matches a handler's 'match' pattern:
183→          - For exec="path/to/file.md": follow the handler type="exec" instructions
184→          - For workflow="path/to/workflow.md": follow the handler type="workflow" instructions
185→          - For action="...": Perform the specified action directly
186→       5. Support both exact matches and fuzzy matching based on the match attribute
187→       6. If no handler matches, prompt user to choose from available options
188→    </handler>
189→`;
190→  }
191→
192→  xml += `      </handlers>
193→    </menu-handlers>
194→
195→    <rules>
196→      <r>ALWAYS communicate in {communication_language} UNLESS contradicted by communication_style.</r>
197→      <r>Stay in character until exit selected</r>
198→      <r>Display Menu items as the item dictates and in the order given.</r>
199→      <r>Load files ONLY when executing a user chosen workflow or a command requires it, EXCEPTION: agent activation step 2 config.yaml</r>
200→    </rules>
201→
202→    <output-discipline critical="MANDATORY">
203→      <r>Keep responses focused: address ONE topic per message, then invite follow-up.</r>
204→      <r>Be concise: use bullet points over paragraphs. If a response exceeds 300 words, split into parts.</r>
205→      <r>Lead with the actionable content. Place context and rationale AFTER the main point.</r>
206→      <r>Never repeat information the user already confirmed. Reference it, do not restate it.</r>
207→      <r>When presenting options, use numbered lists. Maximum 5 options before asking to narrow scope.</r>
208→    </output-discipline>
209→  </activation>
210→`;
211→
212→  return xml;
213→}
214→
215→function buildMenuXml(menuItems) {
216→  let xml = '  <menu>\n';
217→  xml += '    <item cmd="MH or fuzzy match on menu or help">[MH] Redisplay Menu Help</item>\n';
218→
219→  if (menuItems && menuItems.length > 0) {
220→    for (const item of menuItems) {
221→      if (item.trigger) {
222→        const attrs = [`cmd="${item.trigger}"`];
223→        if (item.workflow) attrs.push(`workflow="${item.workflow}"`);
224→        if (item.exec) attrs.push(`exec="${item.exec}"`);
225→        if (item.data) attrs.push(`data="${item.data}"`);
226→        if (item.action) attrs.push(`action="${escapeXml(typeof item.action === 'string' ? item.action : JSON.stringify(item.action))}"`);
227→        xml += `    <item ${attrs.join(' ')}>${escapeXml(item.description || '')}</item>\n`;
228→      }
229→    }
230→  }
231→
232→  xml += '    <item cmd="DA or fuzzy match on exit, leave, goodbye or dismiss agent">[DA] Dismiss Agent</item>\n';
233→  xml += '  </menu>\n';
234→  return xml;
235→}
236→
237→// --- Path Rewriting ---
238→
239→function rewritePaths(content, skfFolder) {
240→  let result = content;
241→  // Handle {bmad_folder} variable form
242→  result = result.replaceAll('{bmad_folder}/skf/', `${skfFolder}/`);
243→  result = result.replaceAll('{project-root}/{bmad_folder}/skf/', `{project-root}/${skfFolder}/`);
244→  // Handle hardcoded _bmad/skf/ form
245→  result = result.replaceAll('_bmad/skf/', `${skfFolder}/`);
246→  return result;
247→}
248→
249→// --- Main Compilation ---
250→
251→function compileAgentFile(yamlPath, options = {}) {
252→  const skfFolder = options.skfFolder || '_bmad/skf';
253→  const rawContent = fs.readFileSync(yamlPath, 'utf8');
254→
255→  // Rewrite paths before parsing
256→  const rewrittenContent = rewritePaths(rawContent, skfFolder);
257→  const agentYaml = yaml.load(rewrittenContent);
258→  const agent = agentYaml.agent;
259→  const meta = agent.metadata;
260→
261→  const basename = path.basename(yamlPath, '.agent.yaml');
262→
263→  let output = '';
264→
265→  // Frontmatter
266→  output += buildFrontmatter(meta, meta.name || basename);
267→
268→  // Start XML code fence
269→  output += '```xml\n';
